def pick_fork(spec):
    if spec.get("corpus_size_tokens", 0) > 2_000_000:
        return "rag"
    if spec.get("style_critical", False) and spec.get("update_frequency_days", 9999) <= 7:
        return "hybrid"
    if spec.get("style_critical", False):
        return "fine_tune"
    if spec.get("update_frequency_days", 9999) <= 7:
        return "rag"
    if spec.get("corpus_size_tokens", 0) <= 2_000_000:
        return "long_context"
    return "rag"

