def evaluate_strategy(product, fork):
    size = product.get("corpus_size_tokens", 0)
    freshness = product.get("update_frequency_days", 9999)
    style = product.get("style_critical", False)
    if fork == "long_context" and size > 2_000_000:
        return (False, "corpus too large for long-context window")
    if fork == "fine_tune" and freshness <= 7:
        return (False, "freshness too high for fine-tune")
    if fork == "rag" and size <= 200_000 and freshness >= 90:
        return (False, "RAG overkill for small stable corpus")
    if fork == "hybrid" and not style:
        return (False, "hybrid wasted without style demand")
    return (True, "fork fits product")

print(f"Harvey + fine_tune:       {evaluate_strategy(harvey, 'fine_tune')}")
print(f"Glean + long_context:     {evaluate_strategy(glean, 'long_context')}")
print(f"Handbook bot + rag:       {evaluate_strategy(handbook_bot, 'rag')}")
